const parseNum = (v) => {
  if (typeof v === 'number') return v;
  if (!v) return 0;
  const m = String(v).replace(/[,$\s]/g, '').match(/(\d+(?:\.\d+)?)([kKmM]?)/);
  if (!m) return 0;
  const n = parseFloat(m[1]);
  const suf = (m[2] || '').toLowerCase();
  return suf === 'm' ? n * 1000000 : suf === 'k' ? n * 1000 : n;
};

const canonicalize = (url) => {
  if (!url) return '';
  try {
    const u = new URL(url);
    u.search = '';
    u.hash = '';
    return u.toString().replace(/\/$/, '');
  } catch (e) { return url; }
};

const out = [];
for (const item of $input.all()) {
  const j = item.json || {};

  const title = j.title || j.header || j.name || '';
  const link = canonicalize(j.url || j.listingUrl || j.urlStub || '');

  const city = j.city || '';
  const state = j.state || j.region || '';
  const location = city && state ? (city + ', ' + state) : (j.location || state || city || '');

  const askingPrice = parseNum(j.askingPrice || j.price);
  const revenue = parseNum(j.grossIncome || j.revenue || j.grossRevenue);

  let sde = parseNum(j.cashFlow);
  if (sde === 0) sde = parseNum(j.ebitda);

  if (sde > 0 && sde < 10000 && revenue > 500000) {
    sde = sde * 1000;
  }

  if (revenue > 100000 && sde > 0 && sde < Math.max(10000, revenue * 0.01)) {
    sde = 0;
  }

  const description = j.description || j.summary || j.adLine || '';
  const industry = j.industry || '';
  const yearEstablished = j.yearEstablished || '';
  const employees = j.employees || '';
  const brokerName = j.brokerName || '';
  const brokerPhone = j.brokerPhone || '';

  let sdeEstimated = false;
  if (sde === 0 && revenue > 0) {
    sde = Math.round(revenue * 0.10);
    sdeEstimated = true;
  }

  if (!title || !link) continue;

  out.push({
    json: { title, source: 'BizQuest', industry, location, askingPrice, revenue, sde, sdeEstimated, listedDate: '', link, description, yearEstablished, numberOfEmployees: employees, reasonForSelling: '', brokerName, brokerPhone, scrapedAt: new Date().toISOString() },
  });
}
return out;

