const out = [];
for (const item of $input.all()) {
  const listing = $('Loop Over Listings').item.json || {};
  const scoreCtx = ($('Score with Claude').item.json || {}).output || {};
  const brokerCtx = ($('Generate Broker Message').item.json || {}).output || {};
  const broker = (brokerCtx.brokerMessage || '[no broker message generated]').trim();

  const fmtUSD = (n) => (typeof n === 'number' && n > 0) ? '$' + n.toLocaleString('en-US') : '—';
  const score = scoreCtx.score || 0;
  const conf = scoreCtx.confidence || 'low';
  const rationale = scoreCtx.rationale || '';
  const scoreEmoji = score >= 4 ? ':large_green_circle:' : ':large_yellow_circle:';

  const buyBoxJson = (($('Define Buy Box').first() || {}).json) || {};
  const keyword = buyBoxJson.keyword || 'deal';

  const title = listing.title || 'Listing';
  const titleLink = listing.link ? ('<' + listing.link + '|' + title + '>') : title;

  const stats = '*Asking:* ' + fmtUSD(listing.askingPrice) + '  |  *Revenue:* ' + fmtUSD(listing.revenue) + '  |  *SDE:* ' + fmtUSD(listing.sde) + (listing.sdeEstimated ? ' _(est.)_' : '');

  const slackText = scoreEmoji + ' *Score ' + score + '/5 (' + conf + ' confidence) — ' + keyword + '*\n'
    + '_' + rationale + '_\n\n'
    + '*' + titleLink + '*\n'
    + ':round_pushpin: ' + (listing.location || '') + '\n\n'
    + stats + '\n\n'
    + '*Drafted broker outreach — hover the code block, click the copy icon:*\n'
    + '```' + broker + '```';

  out.push({ json: { brokerMessage: broker, slackText } });
}
return out;

const items = $input.all();
const ranked = items
  .map(item => ({ json: item.json, _rank: (item.json.sde || 0) }))
  .sort((a, b) => b._rank - a._rank)
  .slice(0, 100)
  .map(({ json }) => ({ json }));
return ranked;
